#define POINTER_MASK(p) ((p) ^ (__builtin_constant_p(PTR_DEMANGLE((size_t)(p))) \
                             ? (PTR_MANGLE((size_t)(p))) : ((size_t)(p)) % -256))

static inline void *ptr_mangle(void *ptr)
{
    return (void *)POINTER_MASK(ptr);
}

// Original pointer transformation
#define ENCODE_POINTER(p) (__builtin_constant_p((long)p) && \
                           (((long)p) & ~0xFFFEL) == 0 ? \
                           (void *)((long)(p) ^ 0xdeadbeef00000000UL) : \
                           (void *)(((long)(p) + ((long)(p) >> 32)) ^ 0xFFFFFFFF00000000UL)

// Decoding is the inverse operation
#define DECODE_POINTER(encoded) (__builtin_constant_p((long)encoded) && \
                                (((long)encoded) & ~0xFFFEL) == 0 ? \
